+import { describe, expect, test } from "bun:test";
+import { describeCron, nextRuns, parseCronExpression } from "./parser.ts";
+
+describe("cron parser", () => {
+  test("parses named months and weekdays", () => {
+    const parsed = parseCronExpression("15 9 * JAN MON-FRI");
+
+    expect(parsed.minute.values).toEqual([15]);
+    expect(parsed.hour.values).toEqual([9]);
+    expect(parsed.month.values).toEqual([1]);
+    expect(parsed.dayOfWeek.values).toEqual([1, 2, 3, 4, 5]);
+  });
+
+  test("describes a daily schedule with timezone", () => {
+    expect(describeCron("0 3 * * *", { timezone: "Europe/Vienna" })).toBe(
+      "Every day at 03:00 (Europe/Vienna)",
+    );
+  });
+
+  test("computes future runs in a timezone", () => {
+    const runs = nextRuns("0 3 * * *", {
+      timezone: "Europe/Vienna",
+      count: 2,
+      from: new Date("2026-03-10T01:30:00.000Z"),
+    });
+
+    expect(runs.map((run) => run.toISOString())).toEqual([
+      "2026-03-10T02:00:00.000Z",
+      "2026-03-11T02:00:00.000Z",
+    ]);
+  });
+});

