+const MONTH_NAMES = new Map([
+  ["JAN", 1],
+  ["FEB", 2],
+  ["MAR", 3],
+  ["APR", 4],
+  ["MAY", 5],
+  ["JUN", 6],
+  ["JUL", 7],
+  ["AUG", 8],
+  ["SEP", 9],
+  ["OCT", 10],
+  ["NOV", 11],
+  ["DEC", 12],
+]);
+
+const WEEKDAY_NAMES = new Map([
+  ["SUN", 0],
+  ["MON", 1],
+  ["TUE", 2],
+  ["WED", 3],
+  ["THU", 4],
+  ["FRI", 5],
+  ["SAT", 6],
+]);
+
+const WEEKDAY_LABELS = [
+  "Sunday",
+  "Monday",
+  "Tuesday",
+  "Wednesday",
+  "Thursday",
+  "Friday",
+  "Saturday",
+];
+
+export interface ParsedCronExpression {
+  expression: string;
+  minute: CronField;
+  hour: CronField;
+  dayOfMonth: CronField;
+  month: CronField;
+  dayOfWeek: CronField;
+}
+
+export interface CronField {
+  kind: "any" | "values";
+  values: number[];
+}
+
+export interface NextRunsOptions {
+  count?: number;
+  from?: Date;
+  timezone?: string;
+}
+
+export function parseCronExpression(expression: string): ParsedCronExpression {
+  const parts = expression.trim().split(/\s+/);
+  if (parts.length !== 5) {
+    throw new Error(`Cron expression must have exactly 5 fields: ${expression}`);
+  }
+
+  return {
+    expression,
+    minute: parseField(parts[0]!, 0, 59),
+    hour: parseField(parts[1]!, 0, 23),
+    dayOfMonth: parseField(parts[2]!, 1, 31),
+    month: parseField(parts[3]!, 1, 12, MONTH_NAMES),
+    dayOfWeek: normalizeWeekdayField(parseField(parts[4]!, 0, 7, WEEKDAY_NAMES)),
+  };
+}
+
+export function describeCron(expression: string, options?: { timezone?: string }): string {
+  const parsed = parseCronExpression(expression);
+  const timezone = options?.timezone;
+  const minute = parsed.minute;
+  const hour = parsed.hour;
+
+  if (isSingleValue(minute) && isSingleValue(hour)) {
+    const base = `Every ${describeDayConstraint(parsed)} at ${pad(hour.values[0]!)}:${pad(minute.values[0]!)}`;
+    return timezone ? `${base} (${timezone})` : base;
+  }
+
+  if (minute.kind === "any" && hour.kind === "any") {
+    const base = `Every minute${describeMonthConstraint(parsed)}${describeDaySuffix(parsed)}`;
+    return timezone ? `${base} (${timezone})` : base;
+  }
+
+  if (hour.kind === "any" && minute.values.length > 1) {
+    const base = `Every hour at minutes ${minute.values.map(pad).join(", ")}${describeMonthConstraint(parsed)}${describeDaySuffix(parsed)}`;
+    return timezone ? `${base} (${timezone})` : base;
+  }
+
+  const base = `Cron schedule ${expression}`;
+  return timezone ? `${base} (${timezone})` : base;
+}
+
+export function nextRuns(expression: string, options?: NextRunsOptions): Date[] {
+  const parsed = parseCronExpression(expression);
+  const count = options?.count ?? 5;
+  const timezone = options?.timezone ?? "UTC";
+  const start = options?.from ?? new Date();
+  const nextDates: Date[] = [];
+
+  let cursor = floorToMinute(start);
+  const maxIterations = 60 * 24 * 366 * 5;
+
+  for (let index = 0; index < maxIterations && nextDates.length < count; index += 1) {
+    cursor = new Date(cursor.getTime() + 60_000);
+    if (matchesCron(parsed, cursor, timezone)) {
+      nextDates.push(cursor);
+    }
+  }
+
+  if (nextDates.length < count) {
+    throw new Error(`Unable to compute ${count} future runs for cron expression: ${expression}`);
+  }
+
+  return nextDates;
+}
+
+export function matchesCron(parsed: ParsedCronExpression, date: Date, timezone: string): boolean {
+  const zoned = getZonedDateParts(date, timezone);
+
+  const minuteMatches = matchesField(parsed.minute, zoned.minute);
+  const hourMatches = matchesField(parsed.hour, zoned.hour);
+  const monthMatches = matchesField(parsed.month, zoned.month);
+  const dayOfMonthMatches = matchesField(parsed.dayOfMonth, zoned.dayOfMonth);
+  const dayOfWeekMatches = matchesField(parsed.dayOfWeek, zoned.dayOfWeek);
+
+  if (!minuteMatches || !hourMatches || !monthMatches) {
+    return false;
+  }
+
+  if (parsed.dayOfMonth.kind === "any" && parsed.dayOfWeek.kind === "any") {
+    return true;
+  }
+
+  if (parsed.dayOfMonth.kind === "any") {
+    return dayOfWeekMatches;
+  }
+
+  if (parsed.dayOfWeek.kind === "any") {
+    return dayOfMonthMatches;
+  }
+
+  return dayOfMonthMatches || dayOfWeekMatches;
+}
+
+function parseField(
+  field: string,
+  min: number,
+  max: number,
+  aliases?: ReadonlyMap<string, number>,
+): CronField {
+  if (field === "*") {
+    return {
+      kind: "any",
+      values: [],
+    };
+  }
+
+  const values = new Set<number>();
+  for (const part of field.split(",")) {
+    addFieldPart(values, part.trim(), min, max, aliases);
+  }
+
+  return {
+    kind: "values",
+    values: Array.from(values).sort((left, right) => left - right),
+  };
+}
+
+function addFieldPart(
+  values: Set<number>,
+  part: string,
+  min: number,
+  max: number,
+  aliases?: ReadonlyMap<string, number>,
+): void {
+  const [base = "", rawStep] = part.split("/");
+  const step = rawStep ? Number.parseInt(rawStep, 10) : 1;
+  if (!Number.isInteger(step) || step < 1) {
+    throw new Error(`Invalid cron step: ${part}`);
+  }
+
+  const [rangeStart, rangeEnd] = base === "*" ? [min, max] : parseRange(base, min, max, aliases);
+  for (let value = rangeStart; value <= rangeEnd; value += step) {
+    values.add(value);
+  }
+}
+
+function parseRange(
+  segment: string,
+  min: number,
+  max: number,
+  aliases?: ReadonlyMap<string, number>,
+): [number, number] {
+  if (!segment.includes("-")) {
+    const value = parseNumericField(segment, aliases);
+    assertRange(value, min, max, segment);
+    return [value, value];
+  }
+
+  const [startSegment, endSegment] = segment.split("-");
+  const start = parseNumericField(startSegment!, aliases);
+  const end = parseNumericField(endSegment!, aliases);
+  assertRange(start, min, max, segment);
+  assertRange(end, min, max, segment);
+  if (end < start) {
+    throw new Error(`Invalid cron range: ${segment}`);
+  }
+
+  return [start, end];
+}
+
+function parseNumericField(value: string, aliases?: ReadonlyMap<string, number>): number {
+  const normalized = value.toUpperCase();
+  if (aliases?.has(normalized)) {
+    return aliases.get(normalized)!;
+  }
+
+  const parsed = Number.parseInt(normalized, 10);
+  if (!Number.isInteger(parsed)) {
+    throw new Error(`Invalid cron field value: ${value}`);
+  }
+
+  return parsed;
+}
+
+function assertRange(value: number, min: number, max: number, source: string): void {
+  if (value < min || value > max) {
+    throw new Error(`Cron field ${source} is outside ${min}-${max}`);
+  }
+}
+
+function normalizeWeekdayField(field: CronField): CronField {
+  if (field.kind === "any") {
+    return field;
+  }
+
+  return {
+    kind: field.kind,
+    values: field.values
+      .map((value) => (value === 7 ? 0 : value))
+      .sort((left, right) => left - right),
+  };
+}
+
+function matchesField(field: CronField, value: number): boolean {
+  return field.kind === "any" || field.values.includes(value);
+}
+
+function isSingleValue(field: CronField): boolean {
+  return field.kind === "values" && field.values.length === 1;
+}
+
+function describeDayConstraint(parsed: ParsedCronExpression): string {
+  if (isSingleValue(parsed.dayOfWeek) && parsed.dayOfMonth.kind === "any") {
+    return WEEKDAY_LABELS[parsed.dayOfWeek.values[0]!]!;
+  }
+
+  if (isSingleValue(parsed.dayOfMonth) && parsed.dayOfWeek.kind === "any") {
+    return `day ${parsed.dayOfMonth.values[0]!} of the month`;
+  }
+
+  if (parsed.dayOfMonth.kind === "any" && parsed.dayOfWeek.kind === "any") {
+    return "day";
+  }
+
+  return `matching day (${parsed.expression.split(/\s+/).slice(2, 5).join(" ")})`;
+}
+
+function describeMonthConstraint(parsed: ParsedCronExpression): string {
+  if (parsed.month.kind === "any") {
+    return "";
+  }
+
+  if (parsed.month.values.length === 1) {
+    return ` in month ${parsed.month.values[0]!}`;
+  }
+
+  return ` in months ${parsed.month.values.join(", ")}`;
+}
+
+function describeDaySuffix(parsed: ParsedCronExpression): string {
+  if (parsed.dayOfMonth.kind === "any" && parsed.dayOfWeek.kind === "any") {
+    return "";
+  }
+
+  if (parsed.dayOfMonth.kind === "any" && isSingleValue(parsed.dayOfWeek)) {
+    return ` on ${WEEKDAY_LABELS[parsed.dayOfWeek.values[0]!]!}`;
+  }
+
+  if (isSingleValue(parsed.dayOfMonth) && parsed.dayOfWeek.kind === "any") {
+    return ` on day ${parsed.dayOfMonth.values[0]!}`;
+  }
+
+  return ` on matching days`;
+}
+
+function floorToMinute(value: Date): Date {
+  const next = new Date(value.getTime());
+  next.setUTCSeconds(0, 0);
+  return next;
+}
+
+function getZonedDateParts(
+  date: Date,
+  timezone: string,
+): {
+  minute: number;
+  hour: number;
+  dayOfMonth: number;
+  month: number;
+  dayOfWeek: number;
+} {
+  const formatter = new Intl.DateTimeFormat("en-US", {
+    timeZone: timezone,
+    hour12: false,
+    weekday: "short",
+    year: "numeric",
+    month: "numeric",
+    day: "numeric",
+    hour: "numeric",
+    minute: "numeric",
+  });
+
+  const parts = formatter.formatToParts(date);
+  const values = new Map<string, string>();
+  for (const part of parts) {
+    if (part.type !== "literal") {
+      values.set(part.type, part.value);
+    }
+  }
+
+  return {
+    minute: Number.parseInt(values.get("minute")!, 10),
+    hour: Number.parseInt(values.get("hour")!, 10),
+    dayOfMonth: Number.parseInt(values.get("day")!, 10),
+    month: Number.parseInt(values.get("month")!, 10),
+    dayOfWeek: WEEKDAY_NAMES.get(values.get("weekday")!.toUpperCase())!,
+  };
+}
+
+function pad(value: number): string {
+  return value.toString().padStart(2, "0");
+}

