+import { fnv1a } from "../utils/hash.ts";
+import { normalizeRetryOptions } from "../utils/retries.ts";
+import type { WorkflowDefinition, WorkflowHandlerContext, WorkflowOptions } from "./types.ts";
+
+export function createWorkflow<TInput, TResult = void>(
+  options: WorkflowOptions<TInput>,
+  handler: (context: WorkflowHandlerContext<TInput>) => TResult | Promise<TResult>,
+): WorkflowDefinition<TInput, TResult> {
+  if (!options.id) {
+    throw new Error("Workflow id is required.");
+  }
+
+  const version = options.version ?? deriveVersion(options);
+  const concurrency = options.concurrency
+    ? {
+        ...options.concurrency,
+      }
+    : null;
+
+  if (concurrency && (!Number.isInteger(concurrency.limit) || concurrency.limit < 1)) {
+    throw new Error("Workflow concurrency limit must be a positive integer.");
+  }
+
+  return Object.freeze({
+    __type: "workflow" as const,
+    id: options.id,
+    version,
+    trigger: options.trigger ?? null,
+    retries: normalizeRetryOptions(options.retries),
+    debounce: options.debounce ?? null,
+    concurrency,
+    handler: async (context: WorkflowHandlerContext<TInput>) => handler(context),
+  });
+}
+
+function deriveVersion<TInput>(options: WorkflowOptions<TInput>): string {
+  const payload = JSON.stringify({
+    id: options.id,
+    trigger:
+      options.trigger && "__type" in options.trigger
+        ? { kind: "event", name: options.trigger.name }
+        : (options.trigger ?? null),
+    retries: options.retries ?? null,
+    debounce: Boolean(options.debounce),
+    concurrency: options.concurrency?.limit ?? null,
+  });
+
+  return fnv1a(payload);
+}

