+import type { DurationInput } from "../utils/duration.ts";
+import type { JsonValue } from "../utils/json.ts";
+import type { NormalizedRetryOptions, WorkflowRetryOptions } from "../utils/retries.ts";
+
+export interface EventDefinition<TPayload> {
+  readonly __type: "event";
+  readonly __payload?: TPayload;
+  readonly name: string;
+}
+
+export interface CronTrigger {
+  cron: string;
+  timezone?: string;
+}
+
+export interface WorkflowDebounce<TInput> {
+  key: (input: TInput) => string;
+  period: DurationInput;
+  timeout?: DurationInput;
+}
+
+export interface WorkflowConcurrency<TInput> {
+  limit: number;
+  key: (input: TInput) => string;
+}
+
+export type WorkflowTrigger<TInput> = EventDefinition<TInput> | CronTrigger;
+
+export interface WorkflowOptions<TInput> {
+  id: string;
+  version?: string;
+  trigger?: WorkflowTrigger<TInput>;
+  retries?: WorkflowRetryOptions;
+  debounce?: WorkflowDebounce<TInput>;
+  concurrency?: WorkflowConcurrency<TInput>;
+}
+
+export interface TriggerEvent<TPayload = unknown> {
+  id: string;
+  name: string;
+  key: string | null;
+  payload: TPayload;
+  createdAt: Date;
+}
+
+export interface WorkflowRunSnapshot<TResult = unknown> {
+  id: string;
+  workflowId: string;
+  version: string;
+  status: WorkflowRunStatus;
+  triggerKind: WorkflowTriggerKind;
+  triggerRef: string | null;
+  eventId: string | null;
+  attempt: number;
+  claimCount: number;
+  availableAt: Date;
+  leaseOwner: string | null;
+  leaseUntil: Date | null;
+  idempotencyKey: string | null;
+  debounceKey: string | null;
+  concurrencyKey: string | null;
+  createdAt: Date;
+  updatedAt: Date;
+  startedAt: Date | null;
+  completedAt: Date | null;
+  input: unknown;
+  result: TResult | null;
+  error: JsonValue | null;
+  cancelRequestedAt: Date | null;
+}
+
+export interface WorkflowStepStateSnapshot<TValue = unknown> {
+  runId: string;
+  stepId: string;
+  kind: DurableStepKind;
+  status: "pending" | "succeeded" | "failed";
+  value: TValue | null;
+  error: JsonValue | null;
+  attemptCount: number;
+  createdAt: Date;
+  updatedAt: Date;
+}
+
+export interface WorkflowWaitOptions {
+  key?: string;
+  timeout?: DurationInput;
+}
+
+export interface WorkflowStepApi {
+  run<TResult>(stepId: string, fn: () => TResult | Promise<TResult>): Promise<TResult>;
+  sleep(stepId: string, duration: DurationInput): Promise<void>;
+  sleepUntil(stepId: string, date: Date): Promise<void>;
+  waitForEvent<TPayload>(
+    event: EventDefinition<TPayload>,
+    options?: WorkflowWaitOptions,
+  ): Promise<TPayload>;
+}
+
+export interface WorkflowHandlerContext<TInput> {
+  input: TInput;
+  event: TriggerEvent | null;
+  run: WorkflowRunSnapshot;
+  signal: AbortSignal;
+  step: WorkflowStepApi;
+}
+
+export interface WorkflowDefinition<TInput, TResult = unknown> {
+  readonly __type: "workflow";
+  readonly id: string;
+  readonly version: string;
+  readonly trigger: WorkflowTrigger<TInput> | null;
+  readonly retries: NormalizedRetryOptions;
+  readonly debounce: WorkflowDebounce<TInput> | null;
+  readonly concurrency: WorkflowConcurrency<TInput> | null;
+  readonly handler: (context: WorkflowHandlerContext<TInput>) => Promise<TResult>;
+}
+
+export type AnyWorkflow = WorkflowDefinition<any, any>;
+export type AnyEvent = EventDefinition<any>;
+export type WorkflowInput<TWorkflow> =
+  TWorkflow extends WorkflowDefinition<infer TInput, any> ? TInput : never;
+export type WorkflowResult<TWorkflow> =
+  TWorkflow extends WorkflowDefinition<any, infer TResult> ? TResult : never;
+export type EventPayload<TEvent> =
+  TEvent extends EventDefinition<infer TPayload> ? TPayload : never;
+
+export type DurableStepKind = "run" | "sleep" | "waitForEvent";
+export type WorkflowRunStatus =
+  | "queued"
+  | "running"
+  | "sleeping"
+  | "waiting"
+  | "completed"
+  | "failed"
+  | "cancelled";
+export type WorkflowTriggerKind = "manual" | "event" | "cron" | "resume";

