+import { CancelledError, WaitForEventTimeoutError } from "../errors.ts";
+import type { AnyWorkflow, WorkflowRunSnapshot } from "../definitions/types.ts";
+import type { DatabaseAdapter } from "../storage/sqlite/DatabaseAdapter.ts";
+import { readSerializedError } from "../storage/sqlite/DatabaseAdapter.ts";
+import { parseDuration, type DurationInput } from "../utils/duration.ts";
+
+class SuspendExecution extends Error {
+  constructor(readonly kind: "sleep" | "wait") {
+    super(kind);
+    this.name = "SuspendExecution";
+  }
+}
+
+export interface ExecutionResult {
+  outcome: "completed" | "suspended" | "cancelled" | "retrying" | "failed";
+  run: WorkflowRunSnapshot;
+  error?: unknown;
+}
+
+export class ReplayExecutor {
+  constructor(private readonly store: DatabaseAdapter) {}
+
+  async execute(workflow: AnyWorkflow, run: WorkflowRunSnapshot): Promise<ExecutionResult> {
+    const abortController = new AbortController();
+    let waitCallIndex = 0;
+
+    const step = {
+      run: async <TResult>(
+        stepId: string,
+        fn: () => TResult | Promise<TResult>,
+      ): Promise<TResult> => {
+        this.throwIfCancelled(run.id);
+
+        const state = this.store.getStepState(run.id, stepId);
+        if (state?.status === "succeeded") {
+          return state.value as TResult;
+        }
+
+        this.store.beginStepAttempt(run.id, stepId, "run");
+        try {
+          const value = await fn();
+          this.store.markStepSucceeded(run.id, stepId, "run", value);
+          return value;
+        } catch (error) {
+          this.store.markStepFailed(run.id, stepId, "run", error);
+          throw error;
+        }
+      },
+      sleep: async (stepId: string, duration: DurationInput): Promise<void> => {
+        this.throwIfCancelled(run.id);
+
+        const state = this.store.getStepState(run.id, stepId);
+        if (state?.status === "succeeded") {
+          return;
+        }
+
+        const wakeAt = Date.now() + parseDuration(duration);
+        this.store.suspendForSleep(run.id, stepId, wakeAt);
+        throw new SuspendExecution("sleep");
+      },
+      sleepUntil: async (stepId: string, date: Date): Promise<void> => {
+        this.throwIfCancelled(run.id);
+
+        const state = this.store.getStepState(run.id, stepId);
+        if (state?.status === "succeeded") {
+          return;
+        }
+
+        const wakeAt = date.getTime();
+        if (!Number.isFinite(wakeAt)) {
+          throw new Error(`Invalid sleepUntil date for step ${stepId}`);
+        }
+
+        this.store.suspendForSleep(run.id, stepId, Math.max(Date.now(), wakeAt));
+        throw new SuspendExecution("sleep");
+      },
+      waitForEvent: async <TPayload>(
+        eventDefinition: { name: string },
+        options?: { key?: string; timeout?: DurationInput },
+      ): Promise<TPayload> => {
+        this.throwIfCancelled(run.id);
+        const stepId = `waitForEvent:${eventDefinition.name}:${waitCallIndex}`;
+        waitCallIndex += 1;
+
+        const state = this.store.getStepState(run.id, stepId);
+        if (
+          state?.status === "succeeded" &&
+          state.value &&
+          typeof state.value === "object" &&
+          !Array.isArray(state.value)
+        ) {
+          return (state.value as { payload: TPayload }).payload;
+        }
+
+        if (state?.status === "failed") {
+          const serializedError = readSerializedError(state.error);
+          if (serializedError?.code === "WAIT_FOR_EVENT_TIMEOUT") {
+            throw new WaitForEventTimeoutError(serializedError.message);
+          }
+        }
+
+        const key = options?.key ?? null;
+        const waitState = this.store.getPendingWait(run.id, stepId);
+        if (waitState && waitState.timeout_at !== null && waitState.timeout_at <= Date.now()) {
