+  config: LocalRuntimeConfig<TWorkflows, TEvents> | RemoteRuntimeConfig<TWorkflows, TEvents>,
+): RuntimeApi<TWorkflows, TEvents> {
+  const workflows = new Map<string, AnyWorkflow>();
+  const workflowsById = new Map<string, AnyWorkflow>();
+  const eventsByName = new Map<string, AnyEvent>();
+  const workflowsByEventName = new Map<string, AnyWorkflow[]>();
+
+  registerDefinitions(
+    config.workflows,
+    config.events,
+    workflows,
+    workflowsById,
+    eventsByName,
+    workflowsByEventName,
+  );
+
+  if ("database" in config && typeof config.database === "string") {
+    return createLocalRuntime(
+      config as LocalRuntimeConfig<TWorkflows, TEvents>,
+      workflows,
+      workflowsById,
+      eventsByName,
+      workflowsByEventName,
