+
+function createLocalRuntime<
+  TWorkflows extends readonly AnyWorkflow[],
+  TEvents extends readonly AnyEvent[],
+>(
+  config: LocalRuntimeConfig<TWorkflows, TEvents>,
+  workflows: Map<string, AnyWorkflow>,
+  workflowsById: Map<string, AnyWorkflow>,
+  eventsByName: Map<string, AnyEvent>,
+  workflowsByEventName: Map<string, AnyWorkflow[]>,
+): RuntimeApi<TWorkflows, TEvents> {
+  const store = new DatabaseAdapter(config.database);
+  store.syncDefinitions([...config.workflows]);
