+  let activeWorker: RuntimeWorkerHandle | null = null;
+
+  const runById = async (
+    workflowId: string,
+    input: unknown,
+    options?: RunOptions,
+  ): Promise<EnqueueRunResult> => {
+    const workflow = workflowsById.get(workflowId);
+    if (!workflow) {
+      throw new Error(`Workflow "${workflowId}" is not registered in this runtime.`);
+    }
