+    return store.enqueueRun(workflow, input, {
+      triggerKind: "manual",
+      idempotencyKey: options?.idempotencyKey ?? null,
+    });
+  };
+
+  const sendByName = async (
+    eventName: string,
+    payload: unknown,
+    options?: SendOptions,
+  ): Promise<StoredEventRecord & { deduplicated: boolean }> => {
+    if (!eventsByName.has(eventName)) {
+      throw new Error(`Event "${eventName}" is not registered in this runtime.`);
+    }
+
+    const storedEvent = store.insertEvent(eventName, payload, {
+      key: options?.key ?? null,
+      idempotencyKey: options?.idempotencyKey ?? null,
+    });
+
+    if (!storedEvent.deduplicated) {
+      store.wakeWaiters(storedEvent);
+      for (const workflow of workflowsByEventName.get(eventName) ?? []) {
+        store.enqueueRun(workflow, payload, {
+          triggerKind: "event",
+          triggerRef: eventName,
