+    const controller = await new WorkerController(store, workflows, options).start();
+    let server: Bun.Server<unknown> | null = null;
+
+    if (config.server) {
+      server = Bun.serve({
+        port: config.server.port,
+        hostname: config.server.hostname ?? "127.0.0.1",
+        fetch: (request) =>
+          handleRuntimeRequest(request, {
+            runById,
+            sendByName,
+            cancel: async (runId) => store.cancelRun(runId),
+            getRun: async (runId) => store.getRun(runId),
+            listRuns: async (limit) => store.listRuns(limit),
+            inspectRun: async (runId) => store.inspectRun(runId),
+            replayRun: async (runId) => store.enqueueReplay(runId),
+          }),
+      });
+    }
+
+    activeWorker = {
+      ownerId: controller.ownerId,
+      url: server ? `http://${server.hostname}:${server.port}` : null,
+      stop: async () => {
+        await controller.stop();
+        server?.stop(true);
+        activeWorker = null;
+      },
+    };
