+    return activeWorker;
+  };
+
+  const send = async <TEvent extends TEvents[number]>(
+    event: TEvent,
+    payload: EventPayload<TEvent>,
+    options?: SendOptions,
+  ): Promise<StoredEventRecord<EventPayload<TEvent>> & { deduplicated: boolean }> =>
+    (await sendByName(event.name, payload, options)) as StoredEventRecord<EventPayload<TEvent>> & {
+      deduplicated: boolean;
+    };
+
+  return {
+    run: async (workflow, input, options) => runById(workflow.id, input, options),
+    send,
+    cancel: async (runId) => store.cancelRun(runId),
+    getRun: async (runId) => store.getRun(runId),
+    listRuns: async (limit) => store.listRuns(limit),
+    inspectRun: async (runId) => store.inspectRun(runId),
+    replayRun: async (runId) => store.enqueueReplay(runId),
+    startWorker,
+  };
+}
+
+function createRemoteRuntime<
+  TWorkflows extends readonly AnyWorkflow[],
+  TEvents extends readonly AnyEvent[],
+>(
+  server: string,
+  workflowsById: Map<string, AnyWorkflow>,
+  eventsByName: Map<string, AnyEvent>,
+): RuntimeApi<TWorkflows, TEvents> {
+  const baseUrl = server.replace(/\/$/, "");
+
+  const send = async <TEvent extends TEvents[number]>(
+    event: TEvent,
+    payload: EventPayload<TEvent>,
+    options?: SendOptions,
+  ): Promise<StoredEventRecord<EventPayload<TEvent>> & { deduplicated: boolean }> => {
+    if (!eventsByName.has(event.name)) {
+      throw new Error(`Event "${event.name}" is not registered in this runtime.`);
+    }
+
+    const result = await fetchJson<SerializedEvent>(`${baseUrl}/events`, {
+      method: "POST",
+      body: JSON.stringify({
+        eventName: event.name,
+        payload,
+        key: options?.key ?? null,
+        idempotencyKey: options?.idempotencyKey ?? null,
+      }),
+    });
+    return reviveEvent(result) as StoredEventRecord<EventPayload<TEvent>> & {
+      deduplicated: boolean;
+    };
+  };
+
+  return {
+    run: async (workflow, input, options) => {
+      if (!workflowsById.has(workflow.id)) {
+        throw new Error(`Workflow "${workflow.id}" is not registered in this runtime.`);
+      }
+
+      return fetchJson<EnqueueRunResult>(`${baseUrl}/runs`, {
+        method: "POST",
+        body: JSON.stringify({
+          workflowId: workflow.id,
+          input,
+          idempotencyKey: options?.idempotencyKey ?? null,
+        }),
+      });
+    },
+    send,
+    cancel: async (runId) => {
+      const result = await fetchJson<SerializedRun | null>(`${baseUrl}/runs/${runId}/cancel`, {
+        method: "POST",
+      });
+      return result ? reviveRun(result) : null;
+    },
+    getRun: async (runId) => {
+      const result = await fetchJson<SerializedRun | null>(`${baseUrl}/runs/${runId}`, {
+        method: "GET",
+      });
+      return result ? reviveRun(result) : null;
+    },
+    listRuns: async (limit) => {
+      const result = await fetchJson<SerializedRun[]>(`${baseUrl}/runs?limit=${limit ?? 100}`, {
+        method: "GET",
+      });
+      return result.map(reviveRun);
+    },
+    inspectRun: async (runId) => {
+      const result = await fetchJson<SerializedInspection | null>(
+        `${baseUrl}/runs/${runId}/inspect`,
+        {
+          method: "GET",
+        },
+      );
+      return result ? reviveInspection(result) : null;
+    },
+    replayRun: async (runId) =>
+      fetchJson<EnqueueRunResult>(`${baseUrl}/runs/${runId}/replay`, {
+        method: "POST",
+      }),
+    startWorker: async () => {
+      throw new Error(
+        "startWorker() is only available for runtimes configured with a local SQLite database.",
+      );
+    },
+  };
+}
+
+function registerDefinitions(
+  workflows: readonly AnyWorkflow[],
+  events: readonly AnyEvent[],
+  workflowMap: Map<string, AnyWorkflow>,
+  workflowsById: Map<string, AnyWorkflow>,
+  eventsByName: Map<string, AnyEvent>,
+  workflowsByEventName: Map<string, AnyWorkflow[]>,
+): void {
+  for (const workflow of workflows) {
+    if (workflowsById.has(workflow.id)) {
+      throw new Error(`Duplicate workflow id "${workflow.id}" in runtime registration.`);
+    }
+
+    workflowMap.set(definitionKey(workflow.id, workflow.version), workflow);
+    workflowMap.set(workflow.id, workflow);
+    workflowsById.set(workflow.id, workflow);
+
+    if (workflow.trigger && "__type" in workflow.trigger) {
+      const items = workflowsByEventName.get(workflow.trigger.name) ?? [];
+      items.push(workflow);
+      workflowsByEventName.set(workflow.trigger.name, items);
+    }
+  }
+
+  for (const event of events) {
+    if (eventsByName.has(event.name)) {
+      throw new Error(`Duplicate event name "${event.name}" in runtime registration.`);
+    }
+
+    eventsByName.set(event.name, event);
+  }
+
+  for (const workflow of workflows) {
+    if (
+      workflow.trigger &&
+      "__type" in workflow.trigger &&
+      !eventsByName.has(workflow.trigger.name)
+    ) {
+      throw new Error(
+        `Workflow "${workflow.id}" depends on event "${workflow.trigger.name}", but that event is not registered in the runtime.`,
+      );
+    }
+  }
+}
+
+type RequestHandlers = {
+  runById(workflowId: string, input: unknown, options?: RunOptions): Promise<EnqueueRunResult>;
+  sendByName(
+    eventName: string,
+    payload: unknown,
+    options?: SendOptions,
+  ): Promise<StoredEventRecord & { deduplicated: boolean }>;
+  cancel(runId: string): Promise<WorkflowRunSnapshot | null>;
+  getRun(runId: string): Promise<WorkflowRunSnapshot | null>;
+  listRuns(limit?: number): Promise<WorkflowRunSnapshot[]>;
+  inspectRun(runId: string): Promise<RunInspectionSnapshot | null>;
+  replayRun(runId: string): Promise<EnqueueRunResult>;
+};
+
+async function handleRuntimeRequest(
+  request: Request,
+  handlers: RequestHandlers,
+): Promise<Response> {
+  const url = new URL(request.url);
+
+  try {
+    if (request.method === "GET" && url.pathname === "/health") {
+      return Response.json({ ok: true });
+    }
+
+    if (request.method === "GET" && url.pathname === "/runs") {
+      const limit = url.searchParams.get("limit");
+      const runs = await handlers.listRuns(limit ? Number.parseInt(limit, 10) : undefined);
+      return Response.json(runs);
+    }
+
+    if (request.method === "POST" && url.pathname === "/runs") {
+      const body = (await request.json()) as {
+        workflowId: string;
+        input: unknown;
+        idempotencyKey?: string | null;
+      };
+      const result = await handlers.runById(
+        body.workflowId,
+        body.input,
+        body.idempotencyKey ? { idempotencyKey: body.idempotencyKey } : undefined,
+      );
+      return Response.json(result, { status: 201 });
+    }
+
+    if (request.method === "POST" && url.pathname === "/events") {
+      const body = (await request.json()) as {
+        eventName: string;
+        payload: unknown;
+        key?: string | null;
+        idempotencyKey?: string | null;
+      };
+      const result = await handlers.sendByName(
+        body.eventName,
+        body.payload,
+        body.key || body.idempotencyKey
+          ? {
+              ...(body.key ? { key: body.key } : {}),
+              ...(body.idempotencyKey ? { idempotencyKey: body.idempotencyKey } : {}),
+            }
+          : undefined,
+      );
+      return Response.json(result, { status: 201 });
+    }
+
+    const pathParts = url.pathname.split("/").filter(Boolean);
+    if (pathParts[0] === "runs" && pathParts.length >= 2) {
+      const runId = decodeURIComponent(pathParts[1]!);
+
+      if (request.method === "GET" && pathParts.length === 2) {
+        return Response.json(await handlers.getRun(runId));
+      }
+
+      if (request.method === "GET" && pathParts[2] === "inspect") {
+        return Response.json(await handlers.inspectRun(runId));
+      }
+
+      if (request.method === "POST" && pathParts[2] === "cancel") {
+        return Response.json(await handlers.cancel(runId));
+      }
+
+      if (request.method === "POST" && pathParts[2] === "replay") {
+        return Response.json(await handlers.replayRun(runId));
+      }
+    }
+
+    return Response.json({ error: "Not found" }, { status: 404 });
+  } catch (error) {
+    const message = error instanceof Error ? error.message : "Unknown runtime error";
+    return Response.json({ error: message }, { status: 400 });
+  }
+}
+
+async function fetchJson<T>(url: string, init: RequestInit): Promise<T> {
+  const response = await fetch(url, {
+    ...init,
+    headers: {
+      "content-type": "application/json",
+      ...init.headers,
+    },
+  });
+
+  if (!response.ok) {
+    const payload = (await response.json().catch(() => ({}))) as { error?: string };
+    throw new Error(payload.error ?? `Request failed with status ${response.status}`);
+  }
+
+  return (await response.json()) as T;
+}
+
+type SerializedRun = Omit<
+  WorkflowRunSnapshot,
+  | "availableAt"
+  | "leaseUntil"
+  | "createdAt"
+  | "updatedAt"
+  | "startedAt"
+  | "completedAt"
+  | "cancelRequestedAt"
+> & {
+  availableAt: string;
+  leaseUntil: string | null;
+  createdAt: string;
+  updatedAt: string;
+  startedAt: string | null;
+  completedAt: string | null;
+  cancelRequestedAt: string | null;
+};
+
+type SerializedEvent = Omit<StoredEventRecord, "createdAt"> & {
+  createdAt: string;
+  deduplicated?: boolean;
+};
+
+type SerializedInspection = {
+  run: SerializedRun;
+  steps: Array<
+    Omit<RunInspectionSnapshot["steps"][number], "createdAt" | "updatedAt"> & {
+      createdAt: string;
+      updatedAt: string;
+    }
+  >;
+  triggerEvent: SerializedEvent | null;
+};
+
+function reviveRun(serialized: SerializedRun): WorkflowRunSnapshot {
+  return {
+    ...serialized,
+    availableAt: new Date(serialized.availableAt),
+    leaseUntil: serialized.leaseUntil ? new Date(serialized.leaseUntil) : null,
+    createdAt: new Date(serialized.createdAt),
+    updatedAt: new Date(serialized.updatedAt),
+    startedAt: serialized.startedAt ? new Date(serialized.startedAt) : null,
+    completedAt: serialized.completedAt ? new Date(serialized.completedAt) : null,
+    cancelRequestedAt: serialized.cancelRequestedAt ? new Date(serialized.cancelRequestedAt) : null,
+  };
+}
+
+function reviveEvent(serialized: SerializedEvent): StoredEventRecord & { deduplicated: boolean } {
+  return {
+    ...serialized,
+    createdAt: new Date(serialized.createdAt),
+    deduplicated: serialized.deduplicated ?? false,
+  };
+}
+
+function reviveInspection(serialized: SerializedInspection): RunInspectionSnapshot {
+  return {
+    run: reviveRun(serialized.run),
+    steps: serialized.steps.map((step) => ({
+      ...step,
+      createdAt: new Date(step.createdAt),
+      updatedAt: new Date(step.updatedAt),
+    })),
+    triggerEvent: serialized.triggerEvent ? reviveEvent(serialized.triggerEvent) : null,
+  };
+}

