+  status: WorkflowRunStatus | "debounced";
+  deduplicated: boolean;
+}
+
+export interface StoredEventRecord<TPayload = unknown> extends TriggerEvent<TPayload> {
+  idempotencyKey: string | null;
+}
+
+export interface RunInspectionSnapshot {
+  run: WorkflowRunSnapshot;
+  steps: WorkflowStepStateSnapshot[];
+  triggerEvent: StoredEventRecord | null;
+}
+
+export interface EnqueueRunOptions {
+  triggerKind: "manual" | "event" | "cron" | "resume";
+  triggerRef?: string | null;
+  eventId?: string | null;
+  idempotencyKey?: string | null;
+}
+
+export class DatabaseAdapter {
+  readonly path: string;
+  readonly db: Database;
+
+  constructor(databaseUrl: string) {
+    this.path = resolveDatabaseLocation(databaseUrl);
+    this.db = new Database(this.path, { create: true });
+    this.configure();
+    this.migrate();
+  }
+
+  close(): void {
+    this.db.close(false);
+  }
+
+  syncDefinitions(workflows: AnyWorkflow[]): void {
+    const now = Date.now();
+    const transaction = this.db.transaction((items: AnyWorkflow[]) => {
+      for (const workflow of items) {
+        const trigger =
+          workflow.trigger === null
+            ? {
+                kind: "manual" as const,
+                eventName: null,
+                cronExpr: null,
+                timezone: null,
+              }
+            : "__type" in workflow.trigger
+              ? {
+                  kind: "event" as const,
+                  eventName: workflow.trigger.name,
+                  cronExpr: null,
+                  timezone: null,
+                }
+              : {
+                  kind: "cron" as const,
+                  eventName: null,
+                  cronExpr: workflow.trigger.cron,
+                  timezone: workflow.trigger.timezone ?? "UTC",
+                };
+
+        this.db
+          .query(
+            `
+              INSERT INTO workflow_definitions (
+                workflow_id,
+                version,
+                trigger_kind,
+                event_name,
+                cron_expr,
+                timezone,
+                created_at,
+                updated_at
+              )
+              VALUES (?, ?, ?, ?, ?, ?, ?, ?)
+              ON CONFLICT(workflow_id, version) DO UPDATE SET
+                trigger_kind = excluded.trigger_kind,
+                event_name = excluded.event_name,
+                cron_expr = excluded.cron_expr,
+                timezone = excluded.timezone,
+                updated_at = excluded.updated_at
+            `,
+          )
+          .run(
+            workflow.id,
+            workflow.version,
+            trigger.kind,
+            trigger.eventName,
+            trigger.cronExpr,
+            trigger.timezone,
+            now,
+            now,
+          );
+
+        if (trigger.kind === "cron" && trigger.cronExpr) {
+          const existing = this.db
+            .query<CronScheduleRow, [string, string]>(
+              `
+                SELECT workflow_id, version, cron_expr, timezone, next_run_at, last_enqueued_at
+                FROM cron_schedules
+                WHERE workflow_id = ? AND version = ?
+              `,
+            )
+            .get(workflow.id, workflow.version);
+
+          const nextRunAt =
+            existing &&
+            existing.cron_expr === trigger.cronExpr &&
+            existing.timezone === trigger.timezone
+              ? existing.next_run_at
+              : nextRuns(trigger.cronExpr, {
+                  timezone: trigger.timezone ?? "UTC",
+                  count: 1,
+                  from: new Date(now),
+                })[0]!.getTime();
+
+          this.db
+            .query(
+              `
+                INSERT INTO cron_schedules (
+                  workflow_id,
+                  version,
+                  cron_expr,
+                  timezone,
+                  next_run_at,
+                  last_enqueued_at
+                )
+                VALUES (?, ?, ?, ?, ?, ?)
+                ON CONFLICT(workflow_id, version) DO UPDATE SET
+                  cron_expr = excluded.cron_expr,
+                  timezone = excluded.timezone,
+                  next_run_at = excluded.next_run_at
+              `,
+            )
+            .run(
+              workflow.id,
+              workflow.version,
+              trigger.cronExpr,
+              trigger.timezone ?? "UTC",
+              nextRunAt,
+              null,
+            );
+        }
+      }
+    });
+
+    transaction(workflows);
+  }
+
+  acquireAuthority(ownerId: string, leaseMs: number): boolean {
+    const now = Date.now();
+    return this.db.transaction(() => {
+      const current = this.db
+        .query<{ owner_id: string; lease_until: number }, [string]>(
+          `
+            SELECT owner_id, lease_until
+            FROM worker_authority
+            WHERE authority_key = ?
+          `,
+        )
+        .get(RUNTIME_AUTHORITY_KEY);
+
+      if (current && current.owner_id !== ownerId && current.lease_until > now) {
+        return false;
+      }
+
+      this.db
+        .query(
+          `
+            INSERT INTO worker_authority (authority_key, owner_id, lease_until, updated_at)
+            VALUES (?, ?, ?, ?)
+            ON CONFLICT(authority_key) DO UPDATE SET
+              owner_id = excluded.owner_id,
+              lease_until = excluded.lease_until,
+              updated_at = excluded.updated_at
+          `,
+        )
+        .run(RUNTIME_AUTHORITY_KEY, ownerId, now + leaseMs, now);
+
+      return true;
+    })();
+  }
+
+  heartbeatAuthority(ownerId: string, leaseMs: number): void {
+    const now = Date.now();
+    this.db
+      .query(
+        `
+          UPDATE worker_authority
+          SET lease_until = ?, updated_at = ?
+          WHERE authority_key = ? AND owner_id = ?
+        `,
+      )
+      .run(now + leaseMs, now, RUNTIME_AUTHORITY_KEY, ownerId);
+  }
+
+  releaseAuthority(ownerId: string): void {
+    this.db
+      .query(
+        `
+          DELETE FROM worker_authority
+          WHERE authority_key = ? AND owner_id = ?
+        `,
+      )
+      .run(RUNTIME_AUTHORITY_KEY, ownerId);
+  }
+
+  enqueueRun(workflow: AnyWorkflow, input: unknown, options: EnqueueRunOptions): EnqueueRunResult {
+    const now = Date.now();
+    const inputJson = toJson(input);
+
+    if (options.idempotencyKey) {
+      const existing = this.db
+        .query<WorkflowRunRow, [string, string]>(
+          `
+            SELECT *
+            FROM workflow_runs
+            WHERE workflow_id = ? AND idempotency_key = ?
+          `,
+        )
+        .get(workflow.id, options.idempotencyKey);
+
+      if (existing) {
+        return {
+          id: existing.id,
+          workflowId: existing.workflow_id,
+          version: existing.version,
+          status: existing.status,
+          deduplicated: true,
+        };
+      }
+    }
+
+    if (workflow.debounce) {
+      return this.enqueueDebouncedRun(workflow, input, inputJson, now, options);
+    }
+
+    const id = crypto.randomUUID();
+    const concurrencyKey = workflow.concurrency ? workflow.concurrency.key(input) : null;
+
+    this.db
+      .query(
+        `
+          INSERT INTO workflow_runs (
+            id,
+            workflow_id,
+            version,
+            trigger_kind,
+            trigger_ref,
+            event_id,
+            input_json,
+            status,
+            attempt,
+            claim_count,
+            lease_generation,
+            available_at,
+            lease_owner,
+            lease_until,
+            idempotency_key,
+            debounce_key,
+            concurrency_key,
+            result_json,
+            error_json,
+            cancel_requested_at,
+            created_at,
+            updated_at,
+            started_at,
+            completed_at
+          )
+          VALUES (?, ?, ?, ?, ?, ?, ?, 'queued', 1, 0, 0, ?, NULL, NULL, ?, NULL, ?, NULL, NULL, NULL, ?, ?, NULL, NULL)
+        `,
+      )
+      .run(
+        id,
+        workflow.id,
+        workflow.version,
+        options.triggerKind,
+        options.triggerRef ?? null,
+        options.eventId ?? null,
+        inputJson,
+        now,
+        options.idempotencyKey ?? null,
+        concurrencyKey,
+        now,
+        now,
+      );
+
+    return {
+      id,
+      workflowId: workflow.id,
+      version: workflow.version,
+      status: "queued",
+      deduplicated: false,
+    };
+  }
+
+  enqueueReplay(originalRunId: string): EnqueueRunResult {
+    const now = Date.now();
+    const original = this.getRunRow(originalRunId);
+    if (!original) {
+      throw new Error(`Run not found: ${originalRunId}`);
+    }
+
+    const id = crypto.randomUUID();
+    this.db
+      .query(
+        `
+          INSERT INTO workflow_runs (
+            id,
+            workflow_id,
+            version,
+            trigger_kind,
+            trigger_ref,
+            event_id,
+            input_json,
+            status,
+            attempt,
+            claim_count,
+            lease_generation,
+            available_at,
+            lease_owner,
+            lease_until,
+            idempotency_key,
+            debounce_key,
+            concurrency_key,
+            result_json,
+            error_json,
+            cancel_requested_at,
+            created_at,
+            updated_at,
+            started_at,
+            completed_at
+          )
+          VALUES (?, ?, ?, 'resume', ?, ?, ?, 'queued', 1, 0, 0, ?, NULL, NULL, NULL, NULL, ?, NULL, NULL, NULL, ?, ?, NULL, NULL)
+        `,
+      )
+      .run(
+        id,
+        original.workflow_id,
+        original.version,
+        original.id,
+        original.event_id,
+        original.input_json,
+        now,
+        original.concurrency_key,
+        now,
+        now,
+      );
+
+    return {
+      id,
+      workflowId: original.workflow_id,
+      version: original.version,
+      status: "queued",
+      deduplicated: false,
+    };
+  }
+
+  insertEvent<TPayload>(
+    eventName: string,
+    payload: TPayload,
+    options?: { key?: string | null; idempotencyKey?: string | null },
+  ): StoredEventRecord<TPayload> & { deduplicated: boolean } {
+    const key = options?.key ?? null;
+    if (options?.idempotencyKey) {
+      const existing = this.db
+        .query<WorkflowEventRow, [string, string]>(
+          `
+            SELECT *
+            FROM workflow_events
+            WHERE name = ? AND idempotency_key = ?
+          `,
+        )
+        .get(eventName, options.idempotencyKey);
+
+      if (existing) {
+        return {
+          ...this.hydrateEvent<TPayload>(existing),
+          deduplicated: true,
+        };
+      }
+    }
+
+    const now = Date.now();
+    const id = crypto.randomUUID();
+    this.db
+      .query(
+        `
+          INSERT INTO workflow_events (id, name, event_key, payload_json, idempotency_key, created_at)
+          VALUES (?, ?, ?, ?, ?, ?)
+        `,
+      )
+      .run(id, eventName, key, toJson(payload), options?.idempotencyKey ?? null, now);
+
+    return {
+      id,
+      name: eventName,
+      key,
+      payload,
+      createdAt: new Date(now),
+      idempotencyKey: options?.idempotencyKey ?? null,
+      deduplicated: false,
+    };
+  }
+
+  wakeWaiters(event: StoredEventRecord): string[] {
+    const now = Date.now();
+    const waits = this.db
+      .query<EventWaitRow, [string, string | null]>(
+        `
+          SELECT run_id, step_id, event_name, event_key, timeout_at, created_at
+          FROM event_waits
+          WHERE event_name = ? AND (event_key IS NULL OR event_key = ?)
+        `,
+      )
+      .all(event.name, event.key);
+
+    const resumedRunIds: string[] = [];
+    const transaction = this.db.transaction((rows: EventWaitRow[]) => {
+      for (const wait of rows) {
+        const run = this.getRunRow(wait.run_id);
+        if (!run || run.status === "cancelled") {
+          this.deleteWait(wait.run_id, wait.step_id);
+          continue;
+        }
+
+        this.db
+          .query(
+            `
+              INSERT INTO step_states (
+                run_id,
+                step_id,
+                kind,
+                status,
+                value_json,
+                error_json,
+                attempt_count,
+                created_at,
+                updated_at
+              )
+              VALUES (?, ?, 'waitForEvent', 'succeeded', ?, NULL, 1, ?, ?)
+              ON CONFLICT(run_id, step_id) DO UPDATE SET
+                status = 'succeeded',
+                value_json = excluded.value_json,
+                error_json = NULL,
+                updated_at = excluded.updated_at
+            `,
+          )
+          .run(wait.run_id, wait.step_id, toJson(event), now, now);
+
+        this.deleteWait(wait.run_id, wait.step_id);
+        this.db
+          .query(
+            `
+              UPDATE workflow_runs
+              SET status = 'queued',
+                available_at = ?,
+                lease_owner = NULL,
+                lease_until = NULL,
+                updated_at = ?
+              WHERE id = ? AND status != 'cancelled'
+            `,
+          )
+          .run(now, now, wait.run_id);
+        resumedRunIds.push(wait.run_id);
+      }
+    });
+
+    transaction(waits);
+    return resumedRunIds;
+  }
+
+  flushDueDebounces(workflows: Map<string, AnyWorkflow>): string[] {
+    const now = Date.now();
+    const rows = this.db
+      .query<DebounceWindowRow, [number]>(
+        `
+          SELECT *
+          FROM debounce_windows
+          WHERE flush_at <= ?
+          ORDER BY flush_at ASC
+        `,
+      )
+      .all(now);
+
+    const createdRunIds: string[] = [];
+    const transaction = this.db.transaction((items: DebounceWindowRow[]) => {
+      for (const row of items) {
+        const workflow =
+          workflows.get(definitionKey(row.workflow_id, row.version)) ??
+          workflows.get(row.workflow_id);
+        if (!workflow) {
+          this.deleteDebounceWindow(row.workflow_id, row.version, row.debounce_key);
+          continue;
+        }
+
+        const input = fromJson<unknown>(row.latest_input_json);
+        const concurrencyKey = workflow.concurrency ? workflow.concurrency.key(input) : null;
+
+        this.db
+          .query(
+            `
+              INSERT OR IGNORE INTO workflow_runs (
+                id,
+                workflow_id,
+                version,
+                trigger_kind,
+                trigger_ref,
+                event_id,
+                input_json,
+                status,
+                attempt,
+                claim_count,
+                lease_generation,
+                available_at,
+                lease_owner,
+                lease_until,
+                idempotency_key,
+                debounce_key,
+                concurrency_key,
+                result_json,
+                error_json,
+                cancel_requested_at,
+                created_at,
+                updated_at,
+                started_at,
+                completed_at
+              )
+              VALUES (?, ?, ?, ?, ?, ?, ?, 'queued', 1, 0, 0, ?, NULL, NULL, NULL, ?, ?, NULL, NULL, NULL, ?, ?, NULL, NULL)
+            `,
+          )
+          .run(
+            row.pending_run_id,
+            row.workflow_id,
+            row.version,
+            row.trigger_kind,
+            row.trigger_ref,
+            row.latest_event_id,
+            row.latest_input_json,
+            now,
+            row.debounce_key,
+            concurrencyKey,
+            now,
+            now,
+          );
+
+        this.deleteDebounceWindow(row.workflow_id, row.version, row.debounce_key);
+        createdRunIds.push(row.pending_run_id);
+      }
+    });
+
+    transaction(rows);
+    return createdRunIds;
+  }
+
+  claimDueRun(
+    workflows: Map<string, AnyWorkflow>,
+    ownerId: string,
+    leaseMs: number,
+  ): WorkflowRunSnapshot | null {
+    const now = Date.now();
+    const candidates = this.db
+      .query<WorkflowRunRow, [number, number]>(
+        `
+          SELECT *
+          FROM workflow_runs
+          WHERE status IN ('queued', 'running', 'sleeping', 'waiting')
+            AND available_at <= ?
+            AND (lease_until IS NULL OR lease_until <= ?)
+          ORDER BY available_at ASC, created_at ASC
+          LIMIT 50
+        `,
+      )
+      .all(now, now);
+
+    for (const candidate of candidates) {
+      const workflow =
+        workflows.get(definitionKey(candidate.workflow_id, candidate.version)) ??
+        workflows.get(candidate.workflow_id);
+      if (!workflow) {
+        continue;
+      }
+
+      if (
+        workflow.concurrency &&
+        !this.canClaimConcurrency(
+          candidate.workflow_id,
+          candidate.concurrency_key,
+          workflow.concurrency.limit,
+          candidate.id,
+        )
+      ) {
+        continue;
+      }
+
+      const success = this.db.transaction(() => {
+        const current = this.getRunRow(candidate.id);
+        if (!current) {
+          return false;
+        }
+
+        const leaseExpired = current.lease_until === null || current.lease_until <= now;
+        if (!leaseExpired || current.available_at > now) {
+          return false;
+        }
+
+        this.db
+          .query(
+            `
+              UPDATE workflow_runs
+              SET status = 'running',
+                claim_count = claim_count + 1,
+                lease_generation = lease_generation + 1,
+                lease_owner = ?,
+                lease_until = ?,
+                attempt = CASE WHEN status = 'running' THEN attempt + 1 ELSE attempt END,
+                updated_at = ?,
+                started_at = COALESCE(started_at, ?)
+              WHERE id = ?
+            `,
+          )
+          .run(ownerId, now + leaseMs, now, now, current.id);
+
+        return true;
+      })();
+
+      if (success) {
+        return this.getRun(candidate.id);
+      }
+    }
+
+    return null;
+  }
+
+  renewRunLease(runId: string, ownerId: string, leaseMs: number): void {
+    const now = Date.now();
+    this.db
+      .query(
+        `
+          UPDATE workflow_runs
+          SET lease_until = ?, updated_at = ?
+          WHERE id = ? AND lease_owner = ? AND status = 'running'
+        `,
+      )
+      .run(now + leaseMs, now, runId, ownerId);
+  }
+
+  getRun(runId: string): WorkflowRunSnapshot | null {
+    const row = this.getRunRow(runId);
+    return row ? this.hydrateRun(row) : null;
+  }
+
+  listRuns(limit = 100): WorkflowRunSnapshot[] {
+    return this.db
+      .query<WorkflowRunRow, [number]>(
+        `
+          SELECT *
+          FROM workflow_runs
+          ORDER BY created_at DESC
+          LIMIT ?
+        `,
+      )
+      .all(limit)
+      .map((row) => this.hydrateRun(row));
