+
+  inspectRun(runId: string): RunInspectionSnapshot | null {
+    const run = this.getRun(runId);
+    if (!run) {
+      return null;
+    }
+
+    const steps = this.db
+      .query<StepStateRow, [string]>(
+        `
+          SELECT *
+          FROM step_states
+          WHERE run_id = ?
+          ORDER BY created_at ASC, step_id ASC
+        `,
+      )
+      .all(runId)
+      .map((row) => this.hydrateStep(row));
+
+    const triggerEvent = run.eventId ? this.getEvent(run.eventId) : null;
+    return { run, steps, triggerEvent };
+  }
+
+  getEvent(eventId: string): StoredEventRecord | null {
+    const row = this.db
+      .query<WorkflowEventRow, [string]>(
+        `
+          SELECT *
+          FROM workflow_events
+          WHERE id = ?
