+
+  beginStepAttempt(runId: string, stepId: string, kind: DurableStepKind): number {
+    const now = Date.now();
+    this.db
+      .query(
+        `
+          INSERT INTO step_states (
+            run_id,
+            step_id,
+            kind,
+            status,
+            value_json,
+            error_json,
+            attempt_count,
+            created_at,
+            updated_at
+          )
+          VALUES (?, ?, ?, 'pending', NULL, NULL, 1, ?, ?)
+          ON CONFLICT(run_id, step_id) DO UPDATE SET
+            kind = excluded.kind,
+            status = 'pending',
+            error_json = NULL,
+            attempt_count = step_states.attempt_count + 1,
+            updated_at = excluded.updated_at
+        `,
+      )
+      .run(runId, stepId, kind, now, now);
+
+    const state = this.getStepState(runId, stepId);
+    return state?.attemptCount ?? 1;
+  }
+
