+
+  markStepFailed(runId: string, stepId: string, kind: DurableStepKind, error: unknown): void {
+    const now = Date.now();
+    this.db
+      .query(
+        `
+          INSERT INTO step_states (
+            run_id,
+            step_id,
+            kind,
+            status,
+            value_json,
+            error_json,
+            attempt_count,
+            created_at,
+            updated_at
+          )
+          VALUES (?, ?, ?, 'failed', NULL, ?, 1, ?, ?)
+          ON CONFLICT(run_id, step_id) DO UPDATE SET
+            kind = excluded.kind,
+            status = 'failed',
+            error_json = excluded.error_json,
