+function resolveDatabaseLocation(databaseUrl: string): string {
+  if (databaseUrl === ":memory:" || databaseUrl === "sqlite://:memory:") {
+    return ":memory:";
+  }
+
+  const pathname = databaseUrl.startsWith("sqlite://")
+    ? databaseUrl.slice("sqlite://".length)
+    : databaseUrl;
+  if (!pathname) {
+    throw new Error(`Invalid database path: ${databaseUrl}`);
+  }
+
+  const absolute = ensureParentDirectory(pathname.startsWith("/") ? pathname : resolve(pathname));
+  return absolute;
+}
+
