+
+export function readSerializedError(value: JsonValue | null): SerializedError | null {
+  if (!value || typeof value !== "object" || Array.isArray(value)) {
+    return null;
+  }
+
+  const maybe = value as Record<string, unknown>;
+  if (typeof maybe.message !== "string" || typeof maybe.name !== "string") {
+    return null;
+  }
+
+  return maybe as unknown as SerializedError;
+}

