+const DURATION_UNITS = new Map<string, number>([
+  ["ms", 1],
+  ["s", 1_000],
+  ["m", 60_000],
+  ["h", 3_600_000],
+  ["d", 86_400_000],
+]);
+
+export type DurationInput = number | `${number}${"ms" | "s" | "m" | "h" | "d"}`;
+
+export function parseDuration(input: DurationInput): number {
+  if (typeof input === "number") {
+    if (!Number.isFinite(input) || input < 0) {
+      throw new Error(`Invalid duration: ${input}`);
+    }
+
+    return input;
+  }
+
+  const match = /^(\d+)(ms|s|m|h|d)$/.exec(input);
+  if (!match) {
+    throw new Error(`Invalid duration: ${input}`);
+  }
+
+  const value = match[1]!;
+  const unit = match[2]!;
+  return Number.parseInt(value, 10) * DURATION_UNITS.get(unit)!;
+}
+
+export function formatDuration(durationMs: number): string {
+  if (durationMs % 86_400_000 === 0) {
+    return `${durationMs / 86_400_000}d`;
+  }
+
+  if (durationMs % 3_600_000 === 0) {
+    return `${durationMs / 3_600_000}h`;
+  }
+
+  if (durationMs % 60_000 === 0) {
+    return `${durationMs / 60_000}m`;
+  }
+
+  if (durationMs % 1_000 === 0) {
+    return `${durationMs / 1_000}s`;
+  }
+
+  return `${durationMs}ms`;
+}

