+export type JsonPrimitive = string | number | boolean | null;
+export type JsonValue = JsonPrimitive | JsonValue[] | { [key: string]: JsonValue };
+
+export interface SerializedError {
+  name: string;
+  message: string;
+  stack?: string;
+  cause?: JsonValue;
+  code?: string;
+}
+
+export function toJson<T>(value: T): string {
+  return JSON.stringify(value);
+}
+
+export function fromJson<T>(value: string | null): T | null {
+  if (value === null) {
+    return null;
+  }
+
+  return JSON.parse(value) as T;
+}
+
+export function serializeError(error: unknown): SerializedError {
+  if (error instanceof Error) {
+    const serialized: SerializedError = {
+      name: error.name,
+      message: error.message,
+    };
+
+    if (error.stack) {
+      serialized.stack = error.stack;
+    }
+
+    const cause = normalizeCause((error as Error & { cause?: unknown }).cause);
+    if (cause !== undefined) {
+      serialized.cause = cause;
+    }
+
+    const code = readErrorCode(error);
+    if (code) {
+      serialized.code = code;
+    }
+
+    return serialized;
+  }
+
+  const serialized: SerializedError = {
+    name: "Error",
+    message: typeof error === "string" ? error : "Unknown error",
+  };
+
+  const cause = normalizeCause(error);
+  if (cause !== undefined) {
+    serialized.cause = cause;
+  }
+
+  return serialized;
+}
+
+export function deserializeError(payload: SerializedError | null): Error | null {
+  if (!payload) {
+    return null;
+  }
+
+  let error: Error;
+
+  switch (payload.code) {
+    case "RUN_CANCELLED":
+      error = new Error(payload.message);
+      error.name = "CancelledError";
+      break;
+    case "WAIT_FOR_EVENT_TIMEOUT":
+      error = new Error(payload.message);
+      error.name = "WaitForEventTimeoutError";
+      break;
+    default:
+      error = new Error(payload.message);
+      error.name = payload.name;
+      break;
+  }
+
+  if (payload.stack) {
+    error.stack = payload.stack;
+  }
+
+  return error;
+}
+
+function readErrorCode(error: Error): string | undefined {
+  if ("code" in error && typeof error.code === "string") {
+    return error.code;
+  }
+
+  return undefined;
+}
+
+function normalizeCause(value: unknown): JsonValue | undefined {
+  if (value === undefined) {
+    return undefined;
+  }
+
+  try {
+    return JSON.parse(JSON.stringify(value)) as JsonValue;
+  } catch {
+    return String(value);
+  }
+}

