+import type { DurationInput } from "./duration.ts";
+import { parseDuration } from "./duration.ts";
+
+export interface WorkflowRetryOptions {
+  attempts?: number;
+  backoff?: "exponential" | "linear";
+  minDelay?: DurationInput;
+  maxDelay?: DurationInput;
+  jitter?: boolean;
+}
+
+export interface NormalizedRetryOptions {
+  attempts: number;
+  backoff: "exponential" | "linear";
+  minDelayMs: number;
+  maxDelayMs: number;
+  jitter: boolean;
+}
+
+export function normalizeRetryOptions(options?: WorkflowRetryOptions): NormalizedRetryOptions {
+  const attempts = options?.attempts ?? 3;
+  if (!Number.isInteger(attempts) || attempts < 1) {
+    throw new Error(`Invalid retry attempts: ${attempts}`);
+  }
+
+  const minDelayMs = parseDuration(options?.minDelay ?? "1s");
+  const maxDelayMs = parseDuration(options?.maxDelay ?? "5m");
+  if (maxDelayMs < minDelayMs) {
+    throw new Error("Retry maxDelay must be greater than or equal to minDelay");
+  }
+
+  return {
+    attempts,
+    backoff: options?.backoff ?? "exponential",
+    minDelayMs,
+    maxDelayMs,
+    jitter: options?.jitter ?? true,
+  };
+}
+
+export function calculateRetryDelay(options: NormalizedRetryOptions, attempt: number): number {
+  const step = Math.max(0, attempt - 1);
+  const baseDelay =
+    options.backoff === "linear" ? options.minDelayMs * (step + 1) : options.minDelayMs * 2 ** step;
+  const bounded = Math.min(options.maxDelayMs, baseDelay);
+  if (!options.jitter || bounded === 0) {
+    return bounded;
+  }
+
+  const lowerBound = Math.floor(bounded * 0.8);
+  const jitterSpread = bounded - lowerBound;
+  return lowerBound + Math.floor(Math.random() * (jitterSpread + 1));
+}

