+  leaseMs?: number;
+  authorityLeaseMs?: number;
+  heartbeatMs?: number;
+}
+
+export interface WorkerHandle {
+  readonly ownerId: string;
+  stop(): Promise<void>;
+}
+
+const DEFAULT_OPTIONS: Required<WorkerStartOptions> = {
+  workers: 1,
+  pollIntervalMs: 50,
+  leaseMs: 5_000,
+  authorityLeaseMs: 10_000,
+  heartbeatMs: 1_000,
+};
+
+export class WorkerController implements WorkerHandle {
+  readonly ownerId = crypto.randomUUID();
+
+  private readonly options: Required<WorkerStartOptions>;
+  private readonly executor: ReplayExecutor;
+  private readonly activeRuns = new Map<string, Promise<void>>();
+  private authorityHeartbeat: Timer | null = null;
+  private loopPromise: Promise<void> | null = null;
+  private stopping = false;
+
+  constructor(
+    private readonly store: DatabaseAdapter,
+    private readonly workflows: Map<string, AnyWorkflow>,
+    options?: WorkerStartOptions,
+  ) {
+    this.options = {
+      ...DEFAULT_OPTIONS,
+      ...options,
+    };
+    this.executor = new ReplayExecutor(store);
+  }
+
+  async start(): Promise<this> {
+    const acquired = this.store.acquireAuthority(this.ownerId, this.options.authorityLeaseMs);
+    if (!acquired) {
+      throw new Error("Another worker already owns this SQLite database.");
+    }
+
+    this.authorityHeartbeat = setInterval(() => {
+      this.store.heartbeatAuthority(this.ownerId, this.options.authorityLeaseMs);
+    }, this.options.heartbeatMs);
+
+    this.loopPromise = this.loop();
+    return this;
+  }
+
+  async stop(): Promise<void> {
+    this.stopping = true;
+    if (this.loopPromise) {
+      await this.loopPromise;
+    }
+  }
+
+  private async loop(): Promise<void> {
+    try {
+      while (!this.stopping) {
+        this.store.flushDueDebounces(this.workflows);
+        this.store.pollDueCrons(this.workflows);
+
+        let claimedAny = false;
+        while (!this.stopping && this.activeRuns.size < this.options.workers) {
+          const run = this.store.claimDueRun(this.workflows, this.ownerId, this.options.leaseMs);
+          if (!run) {
+            break;
+          }
+
+          claimedAny = true;
+          const task = this.processRun(run.id).finally(() => {
+            this.activeRuns.delete(run.id);
+          });
+          this.activeRuns.set(run.id, task);
+        }
+
+        if (!claimedAny) {
+          await Bun.sleep(this.options.pollIntervalMs);
+        }
+      }
+
+      await Promise.allSettled(this.activeRuns.values());
+    } finally {
+      if (this.authorityHeartbeat) {
+        clearInterval(this.authorityHeartbeat);
+        this.authorityHeartbeat = null;
+      }
+
+      this.store.releaseAuthority(this.ownerId);
+    }
+  }
+
+  private async processRun(runId: string): Promise<void> {
+    const run = this.store.getRun(runId);
+    if (!run) {
+      return;
+    }
+
+    const workflow =
+      this.workflows.get(`${run.workflowId}:${run.version}`) ?? this.workflows.get(run.workflowId);
+    if (!workflow) {
+      return;
+    }
+
+    const heartbeat = setInterval(() => {
+      this.store.renewRunLease(run.id, this.ownerId, this.options.leaseMs);
+    }, this.options.heartbeatMs);
+
+    try {
+      await this.executor.execute(workflow, run);
+    } finally {
+      clearInterval(heartbeat);
+    }
+  }
+}

