+import { mkdtempSync } from "node:fs";
+import { join } from "node:path";
+import { tmpdir } from "node:os";
+import type { RuntimeWorkerHandle, WorkflowRunSnapshot } from "../src/index.ts";
+
+export function createTempDatabaseUrl(name: string): string {
+  const directory = mkdtempSync(join(tmpdir(), "bun-workflow-"));
+  return `sqlite://${join(directory, `${name}.sqlite`)}`;
+}
+
+export async function waitForRunStatus(
+  runtime: {
+    getRun(runId: string): Promise<WorkflowRunSnapshot | null>;
+  },
+  runId: string,
+  statuses: WorkflowRunSnapshot["status"][],
+  timeoutMs = 5_000,
+): Promise<WorkflowRunSnapshot> {
+  const deadline = Date.now() + timeoutMs;
+
+  while (Date.now() < deadline) {
+    const run = await runtime.getRun(runId);
+    if (run && statuses.includes(run.status)) {
+      return run;
+    }
+
+    await Bun.sleep(10);
+  }
+
+  const latest = await runtime.getRun(runId);
+  throw new Error(
+    `Run ${runId} did not reach one of: ${statuses.join(", ")}. Last status: ${latest?.status ?? "missing"}`,
+  );
+}
+
+export async function stopWorker(worker: RuntimeWorkerHandle | null): Promise<void> {
+  if (worker) {
+    await worker.stop();
+  }
+}

