+  test("replays completed steps across retries", async () => {
+    let outsideAttempts = 0;
+    let durableExecutions = 0;
+
+    const workflow = createWorkflow<
+      { accountId: string },
+      { token: string; outsideAttempts: number; durableExecutions: number }
+    >(
+      {
+        id: "replay-retry",
+        retries: {
+          attempts: 2,
+          minDelay: "10ms",
+          maxDelay: "10ms",
+          jitter: false,
+        },
+      },
+      async ({ input, step }) => {
+        outsideAttempts += 1;
+
+        const token = await step.run("durable-step", async () => {
+          durableExecutions += 1;
+          return `token:${input.accountId}`;
+        });
+
+        if (outsideAttempts === 1) {
+          throw new Error("fail once");
+        }
+
+        return {
+          token,
+          outsideAttempts,
+          durableExecutions,
+        };
+      },
+    );
+
+    const runtime = createRuntime({
+      database: createTempDatabaseUrl("replay-retry"),
+      workflows: [workflow],
+      events: [],
+    });
+
+    const worker = await runtime.startWorker({
+      workers: 1,
+      pollIntervalMs: 5,
+      leaseMs: 100,
+      heartbeatMs: 10,
+    });
+
+    try {
+      const queued = await runtime.run(workflow, { accountId: "acc_1" });
+      const completed = await waitForRunStatus(runtime, queued.id, ["completed"]);
+      const inspection = await runtime.inspectRun(queued.id);
+
+      expect(completed.attempt).toBe(2);
+      expect(completed.result).toEqual({
+        token: "token:acc_1",
+        outsideAttempts: 2,
+        durableExecutions: 1,
+      });
+      expect(outsideAttempts).toBe(2);
+      expect(durableExecutions).toBe(1);
+      expect(inspection?.steps).toHaveLength(1);
+      expect(inspection?.steps[0]?.attemptCount).toBe(1);
+    } finally {
+      await stopWorker(worker);
+    }
+  });
+
